 	getAll(): Promise<AgentSession[]> {
 		const raw = this.workspaceState.get<unknown[]>(SESSIONS_KEY);
 		if (!Array.isArray(raw)) {
 			return Promise.resolve([]);
 		}
 		const valid: AgentSession[] = [];
 		for (const entry of raw) {
 			if (isValidAgentSession(entry)) {
